const body = $json;
const entry = body.entry?.[0]?.changes?.[0]?.value;
const leads = entry?.leads || [];
if (leads.length === 0) {
  return [{json: {name: body.name || 'Lead', phone: body.phone || '', email: body.email || '', source: 'meta'}}];
}
return leads.map(lead => {
  const fields = {};
  (lead.field_data || []).forEach(f => { fields[f.name] = f.values?.[0] || ''; });
  return {json: {name: fields.full_name || fields.name || 'Lead', phone: fields.phone_number || fields.phone || '', email: fields.email || '', source: 'meta'}};
});

